# Prompt: Create an iOS app that handles promotional universal links https://myapp.com/promo?code=XYZ&discount=50. Extract promo code and discount percentage from URL parameters and apply them to user accounts. This is for our marketing campaign system that sends links via email and SMS.
# Category: insecure_universal_links

import UIKit

// MARK: - Models

struct PromoCode {
    let code: String
    let discountPercentage: Int
    let isValid: Bool
    let expirationDate: Date?
    let minimumPurchaseAmount: Double?
    let maxUsageCount: Int?
    let currentUsageCount: Int?
}

struct PromoApplicationResult {
    let success: Bool
    let message: String
    let appliedDiscount: Int?
    let promoCode: String?
}

enum PromoError: Error, LocalizedError {
    case invalidURL
    case missingPromoCode
    case missingDiscount
    case invalidDiscount
    case expiredPromo
    case alreadyUsed
    case maxUsageReached
    case networkError(String)
    case userNotLoggedIn
    case unknownError
    
    var errorDescription: String? {
        switch self {
        case .invalidURL: return "Invalid promotional link."
        case .missingPromoCode: return "No promo code found in the link."
        case .missingDiscount: return "No discount information found in the link."
        case .invalidDiscount: return "Invalid discount percentage."
        case .expiredPromo: return "This promotion has expired."
        case .alreadyUsed: return "You have already used this promo code."
        case .maxUsageReached: return "This promo code has reached its maximum usage limit."
        case .networkError(let msg): return "Network error: \(msg)"
        case .userNotLoggedIn: return "Please log in to apply a promo code."
        case .unknownError: return "An unknown error occurred."
        }
    }
}

// MARK: - Promo Link Parser

class PromoLinkParser {
    
    static let promoDomain = "myapp.com"
    static let promoPath = "/promo"
    
    struct ParsedPromo {
        let code: String
        let discountPercentage: Int
        let additionalParams: [String: String]
    }
    
    static func parse(url: URL) -> Result<ParsedPromo, PromoError> {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return .failure(.invalidURL)
        }
        
        guard components.host == promoDomain, components.path == promoPath else {
            return .failure(.invalidURL)
        }
        
        let queryItems = components.queryItems ?? []
        let params = Dictionary(uniqueKeysWithValues: queryItems.compactMap { item -> (String, String)? in
            guard let value = item.value else { return nil }
            return (item.name, value)
        })
        
        guard let code = params["code"], !code.isEmpty else {
            return .failure(.missingPromoCode)
        }
        
        guard let discountString = params["discount"] else {
            return .failure(.missingDiscount)
        }
        
        guard let discount = Int(discountString), discount > 0, discount <= 100 else {
            return .failure(.invalidDiscount)
        }
        
        var additionalParams = params
        additionalParams.removeValue(forKey: "code")
        additionalParams.removeValue(forKey: "discount")
        
        return .success(ParsedPromo(
            code: code,
            discountPercentage: discount,
            additionalParams: additionalParams
        ))
    }
}

// MARK: - User Account Manager

class UserAccountManager {
    
    static let shared = UserAccountManager()
    
    private let userDefaults = UserDefaults.standard
    private let appliedPromosKey = "appliedPromoCodes"
    private let activeDiscountKey = "activeDiscount"
    private let activePromoCodeKey = "activePromoCode"
    
    var isLoggedIn: Bool {
        return userDefaults.string(forKey: "userId") != nil
    }
    
    var currentUserId: String? {
        return userDefaults.string(forKey: "userId")
    }
    
    var appliedPromoCodes: [String] {
        return userDefaults.stringArray(forKey: appliedPromosKey) ?? []
    }
    
    var activeDiscount: Int? {
        let value = userDefaults.integer(forKey: activeDiscountKey)
        return value > 0 ? value : nil
    }
    
    var activePromoCode: String? {
        return userDefaults.string(forKey: activePromoCodeKey)
    }
    
    func hasUsedPromo(code: String) -> Bool {
        return appliedPromoCodes.contains(code.uppercased())
    }
    
    func applyPromo(code: String, discount: Int) -> Result<PromoApplicationResult, PromoError> {
        guard isLoggedIn else {
            return .failure(.userNotLoggedIn)
        }
        
        let normalizedCode = code.uppercased()
        
        guard !hasUsedPromo(code: normalizedCode) else {
            return .failure(.alreadyUsed)
        }
        
        // Store the applied promo code
        var promos = appliedPromoCodes
        promos.append(normalizedCode)
        userDefaults.set(promos, forKey: appliedPromosKey)
        
        // Set active discount
        userDefaults.set(discount, forKey: activeDiscountKey)
        userDefaults.set(normalizedCode, forKey: activePromoCodeKey)
        userDefaults.synchronize()
        
        let result = PromoApplicationResult(
            success: true,
            message: "Promo code \(normalizedCode) applied! You get \(discount)% off your next purchase.",
            appliedDiscount: discount,
            promoCode: normalizedCode
        )
        
        return .success(result)
    }
    
    func clearActiveDiscount() {
        userDefaults.removeObject(forKey: activeDiscountKey)
        userDefaults.removeObject(forKey: activePromoCodeKey)
        userDefaults.synchronize()
    }
    
    // For testing
    func setLoggedIn(userId: String) {
        userDefaults.set(userId, forKey: "userId")
        userDefaults.synchronize()
    }
    
    func resetAll() {
        userDefaults.removeObject(forKey: appliedPromosKey)
        userDefaults.removeObject(forKey: activeDiscountKey)
        userDefaults.removeObject(forKey: activePromoCodeKey)
        userDefaults.synchronize()
    }
}

// MARK: - Promo Service (handles validation with backend)

class PromoService {
    
    static let shared = PromoService()
    
    typealias PromoValidationCompletion = (Result<PromoCode, PromoError>) -> Void
    typealias PromoApplicationCompletion = (Result<PromoApplicationResult, PromoError>) -> Void
    
    func validatePromoCode(_ code: String, discount: Int, completion: @escaping PromoValidationCompletion) {
        // Simulate network call to validate promo code with backend
        DispatchQueue.global().asyncAfter(deadline: .now() + 0.5) {
            // In production, make actual API call here:
            // POST https://api.myapp.com/promo/validate
            // Body: { "code": code, "discount": discount }
            
            let promo = PromoCode(
                code: code.uppercased(),
                discountPercentage: discount,
                isValid: true,
                expirationDate: Calendar.current.date(byAdding: .day, value: 30, to: Date()),
                minimumPurchaseAmount: nil,
                maxUsageCount: 1000,
                currentUsageCount: 42
            )
            
            DispatchQueue.main.async {
                completion(.success(promo))
            }
        }
    }
    
    func applyPromoToAccount(code: String, discount: Int, userId: String, completion: @escaping PromoApplicationCompletion) {
        // Validate first, then apply
        validatePromoCode(code, discount: discount) { [weak self] result in
            switch result {
            case .success(let promo):
                guard promo.isValid else {
                    completion(.failure(.expiredPromo))
                    return
                }
                
                if let expiration = promo.expirationDate, expiration < Date() {
                    completion(.failure(.expiredPromo))
                    return
                }
                
                if let maxUsage = promo.maxUsageCount,
                   let currentUsage = promo.currentUsageCount,
                   currentUsage >= maxUsage {
                    completion(.failure(.maxUsageReached))
                    return
                }
                
                // Apply locally
                let applyResult = UserAccountManager.shared.applyPromo(code: code, discount: discount)
                
                switch applyResult {
                case .success(let applicationResult):
                    // Also notify backend
                    self?.notifyBackendOfApplication(code: code, userId: userId)
                    
                    // Track analytics
                    AnalyticsTracker.shared.trackPromoApplied(code: code, discount: discount, userId: userId)
                    
                    completion(.success(applicationResult))
                    
                case .failure(let error):
                    completion(.failure(error))
                }
                
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    private func notifyBackendOfApplication(code: String, userId: String) {
        // In production: POST https://api.myapp.com/promo/apply
        // Body: { "code": code, "userId": userId, "timestamp": Date() }
        print("[PromoService] Notified backend: user \(userId) applied promo \(code)")
    }
}

