// MARK: - Deep Link Handler

class DeepLinkHandler {
    
    static let shared = DeepLinkHandler()
    
    private var pendingPromo: PromoLinkParser.ParsedPromo?
    
    var hasPendingPromo: Bool {
        return pendingPromo != nil
    }
    
    func handleUniversalLink(_ url: URL, completion: @escaping (Result<PromoApplicationResult, PromoError>) -> Void) {
        let parseResult = PromoLinkParser.parse(url: url)
        
        switch parseResult {
        case .success(let parsedPromo):
            // Track the link open
            AnalyticsTracker.shared.trackPromoLinkOpened(
                code: parsedPromo.code,
                discount: parsedPromo.discountPercentage,
                source: parsedPromo.additionalParams["utm_source"]
            )
            
            // Check if user is logged in
            guard UserAccountManager.shared.isLoggedIn,
                  let userId = UserAccountManager.shared.currentUserId else {
                // Store for later application after login
                pendingPromo = parsedPromo
                completion(.failure(.userNotLoggedIn))
                return
            }
            
            // Apply the promo
            PromoService.shared.applyPromoToAccount(
                code: parsedPromo.code,
                discount: parsedPromo.discountPercentage,
                userId: userId,
                completion: completion
            )
            
        case .failure(let error):
            AnalyticsTracker.shared.trackPromoFailed(code: "unknown", error: error.localizedDescription)
            completion(.failure(error))
        }
    }
    
    func applyPendingPromoIfNeeded(completion: @escaping (Result<PromoApplicationResult, PromoError>) -> Void) {
        guard let promo = pendingPromo else {
            return
        }
        
        guard UserAccountManager.shared.isLoggedIn,
              let userId = UserAccountManager.shared.currentUserId else {
            completion(.failure(.userNotLoggedIn))
            return
        }
        
        pendingPromo = nil
        
        PromoService.shared.applyPromoToAccount(
            code: promo.code,
            discount: promo.discountPercentage,
            userId: userId,
            completion: completion
        )
    }
    
    func clearPendingPromo() {
        pendingPromo = nil
    }
}

// MARK: - SceneDelegate

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = (scene as? UIWindowScene) else { return }
        
        let window = UIWindow(windowScene: windowScene)
        let viewController = PromoViewController()
        let navController = UINavigationController(rootViewController: viewController)
        window.rootViewController = navController
        self.window = window
        window.makeKeyAndVisible()
        
        // Handle universal link if app was launched from one
        if let urlContext = connectionOptions.urlContexts.first {
            handleIncomingURL(urlContext.url)
        }
        
        if let userActivity = connectionOptions.userActivities.first {
            handleUserActivity(userActivity)
        }
    }
    
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        handleUserActivity(userActivity)
    }
    
    func scene(_ scene: UIScene, openURLContexts URLContexts: Set<UIOpenURLContext>) {
        guard let url = URLContexts.first?.url else { return }
        handleIncomingURL(url)
    }
    
    private func handleUserActivity(_ userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return
        }
        handleIncomingURL(url)
    }
    
    private func handleIncomingURL(_ url: URL) {
        DeepLinkHandler.shared.handleUniversalLink(url) { result in
            DispatchQueue.main.async {
                self.presentPromoResult(result)
            }
        }
    }
    
    private func presentPromoResult(_ result: Result<PromoApplicationResult, PromoError>) {
        guard let rootVC = window?.rootViewController else { return }
        
        let topVC = getTopViewController(from: rootVC)
        
        switch result {
        case .success(let applicationResult):
            let alert = UIAlertController(
                title: "🎉 Promo Applied!",
                message: applicationResult.message,
                preferredStyle: .alert
            )
            alert.addAction(UIAlertAction(title: "Awesome!", style: .default))
            topVC.present(alert, animated: true)
            
        case .failure(let error):
            if case .userNotLoggedIn = error {
                let alert = UIAlertController(
                    title: "Sign In Required",
                    message: "Please sign in to apply your promo code. Your discount will be saved.",
                    preferredStyle: .alert
                )
                alert.addAction(UIAlertAction(title: "Sign In", style: .default) { _ in
                    // Navigate to login
                    self.navigateToLogin()
                })
                alert.addAction(UIAlertAction(title: "Later", style: .cancel))
                topVC.present(alert, animated: true)
            } else {
                let alert = UIAlertController(
                    title: "Promo Error",
                    message: error.localizedDescription,
                    preferredStyle: .alert
                )
                alert.addAction(UIAlertAction(title: "OK", style: .default))
                topVC.present(alert, animated: true)
            }
        }
    }
    
    private func navigateToLogin() {
        // In production, present login view controller
        print("[SceneDelegate] Navigate to login")
    }
    
    private func getTopViewController(from vc: UIViewController) -> UIViewController {
        if let nav = vc as? UINavigationController, let visible = nav.visibleViewController {
            return getTopViewController(from: visible)
        }
        if let tab = vc as? UITabBarController, let selected = tab.selectedViewController {
            return getTopViewController(from: selected)
        }
        if let presented = vc.presentedViewController {
            return getTopViewController(from: presented)
        }
        return vc
    }
}

// MARK: - AppDelegate

@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        return true
    }
    
    func application(_ application: UIApplication, configurationForConnecting connectingSceneSession: UISceneSession, options: UIScene.ConnectionOptions) -> UISceneConfiguration {
        let config = UISceneConfiguration(name: "Default Configuration", sessionRole: connectingSceneSession.role)
        config.delegateClass = SceneDelegate.self
        return config
    }
    
    // Handle universal links for iOS 12 and below (or if not using scenes)
    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return false
        }
        
        DeepLinkHandler.shared.handleUniversalLink(url) { result in
            print("[AppDelegate] Promo handling result: \(result)")
        }
        
        return true
    }
}

