    }
    
    @objc private func applyManualPromo() {
        guard let code = manualCodeField.text, !code.isEmpty else {
            showAlert(title: "Error", message: "Please enter a promo code")
            return
        }
        
        // Construct URL and process
        let urlString = "https://myapp.com/promo?code=\(code)&discount=20"
        guard let url = URL(string: urlString) else {
            showAlert(title: "Error", message: "Invalid promo code format")
            return
        }
        
        processPromoURL(url)
    }
    
    @objc private func simulateUniversalLink() {
        let url = URL(string: "https://myapp.com/promo?code=SUMMER2024&discount=25&utm_source=email")!
        processPromoURL(url)
    }
    
    @objc private func simulateVIPLink() {
        let url = URL(string: "https://myapp.com/promo?code=VIP50&discount=50&utm_source=email")!
        processPromoURL(url)
    }
    
    @objc private func simulateFlashLink() {
        let url = URL(string: "https://myapp.com/promo?code=FLASH75&discount=75&utm_source=sms")!
        processPromoURL(url)
    }
    
    private func processPromoURL(_ url: URL) {
        activityIndicator.startAnimating()
        view.isUserInteractionEnabled = false
        
        DeepLinkHandler.shared.handleUniversalLink(url) { [weak self] result in
            guard let self = self else { return }
            
            self.activityIndicator.stopAnimating()
            self.view.isUserInteractionEnabled = true
            
            switch result {
            case .success(let applicationResult):
                self.updateUI()
                self.manualCodeField.text = ""
                self.showAlert(title: "🎉 Success!", message: applicationResult.message)
                
                // Haptic feedback
                let generator = UINotificationFeedbackGenerator()
                generator.notificationOccurred(.success)
                
            case .failure(let error):
                self.showAlert(title: "Error", message: error.localizedDescription)
                
                let generator = UINotificationFeedbackGenerator()
                generator.notificationOccurred(.error)
            }
        }
    }
    
    @objc private func resetPromos() {
        let alert = UIAlertController(
            title: "Reset All Promos",
            message: "This will clear all applied promo codes and active discounts. Continue?",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "Reset", style: .destructive) { [weak self] _ in
            UserAccountManager.shared.resetAll()
            self?.updateUI()
        })
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        present(alert, animated: true)
    }
    
    private func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}